// Raft leader election (simplified follower/candidate loop)
for {
    switch node.state {
    case Follower:
        select {
        case <-node.heartbeat:
            node.resetElectionTimer()   // leader alive
        case <-node.electionTimeout:
            node.state = Candidate       // no heartbeat -> run
        }
    case Candidate:
        node.currentTerm++
        node.votedFor = node.id
        votes := 1                       // vote for self
        for _, peer := range node.peers {
            if peer.RequestVote(node.currentTerm, node.lastLogIndex) {
                votes++
            }
        }
        if votes > len(node.peers)/2 {   // majority
            node.state = Leader
            node.sendHeartbeats()
        } else {
            node.resetElectionTimer()    // split vote, retry
        }
    case Leader:
        node.appendEntriesToFollowers()  // replicate log + heartbeat
    }
}
